import React, { useEffect, useState } from "react";
import "../index.css";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const Shop = () => {
  const [products, setProducts] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/products")
      .then((res) => setProducts(res.data))
      .catch((err) => console.error("Error fetching products:", err));
  }, []);

  const handleBuyNow = (product) => {
    // ✅ FIXED: Template literal should use backticks, not quotes
    navigate('/checkout/${product._id}');
  };

  return (
    <section className="shop-section">
      <h2 className="section-title">All Products</h2>

      <div className="products-grid">
        {products.map((product) => (
          <div key={product._id} className="product-card">
            {/* Image section on the LEFT */}
            <div className="image-box">
              <img src={product.image} alt={product.name} />
            </div>

            {/* Details section on the RIGHT */}
            <div className="product-details">
              <h3 className="product-name">{product.name}</h3>

              <div className="product-rating">
                {Array.from({ length: 5 }, (_, i) => (
                  <span
                    key={i}
                    className={i < Math.floor(product.rating || 0) ? "star filled" : "star"}
                  >
                    ★
                  </span>
                ))}
                <span className="rating-value">{product.rating || "N/A"}</span>
              </div>

              <p className="product-desc">{product.description}</p>

              <div className="product-price">₹{product.price}</div>

              <button className="buy-btn" onClick={() => handleBuyNow(product)}>
                Buy Now
              </button>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Shop;
